    {"id": "py_103", "section": "Basics", "source": "https://docs.python.org/3/", "question": "Explain mutable vs immutable data types in Python with examples.", "expected_answer": "Mutable: list, dict, set (can change in place). Immutable: int, str, tuple, frozenset (cannot change after creation, operations create new objects).", "difficulty": "Basic", "category": "Basics"},
    {"id": "py_104", "section": "Basics", "source": "https://docs.python.org/3/", "question": "What is the difference between shallow copy and deep copy?", "expected_answer": "Shallow copy (copy.copy) copies the outer object but nested objects are shared references; deep copy (copy.deepcopy) recursively copies nested objects too.", "difficulty": "Intermediate", "category": "Basics"},
